const items = $input.all();

if (!items || items.length === 0) {
  throw new Error('The S3 node returned no items.');
}

const item = items[0];
const binary = item.binary || {};

let propertyName;
if ('data' in binary) {
  propertyName = 'data';
} else {
  const keys = Object.keys(binary);
  propertyName = keys.length > 0 ? keys[0] : null;
}

if (!propertyName) {
  throw new Error('The S3 node did not return config.json as binary data.');
}

const rawBuffer = await this.helpers.getBinaryDataBuffer(0, propertyName);
const raw = rawBuffer.toString('utf8').replace(/^\uFEFF/, '');

let config;
try {
  config = JSON.parse(raw);
} catch (error) {
  throw new Error(`Could not parse s3://prompt-monitor-assets/config.json: ${error.message}`);
}

const users = config.users;
const prompts = config.prompts;

if (!Array.isArray(users)) {
  throw new Error('config.users must be an array.');
}

if (!Array.isArray(prompts)) {
  throw new Error('config.prompts must be an array.');
}

const usersById = {};
for (const user of users) {
  usersById[String(user.id)] = user;
}

const output = [];

for (let index = 0; index < prompts.length; index++) {
  const promptData = prompts[index];
  const userId = promptData.user_id;
  const user = usersById[String(userId)];

  if (!user) {
    throw new Error(`No user found for prompts[${index}].user_id=${userId}`);
  }

  const username = user.username;
  const promptName = promptData.name;
  const topic = promptData.topic;
  const promptText = promptData.prompt;

  if (!username) {
    throw new Error(`Missing username for user ID ${userId}`);
  }

  if (!promptName || !topic || !promptText) {
    throw new Error(`Incomplete prompt data at prompts[${index}]`);
  }

  output.push({
    json: {
      user_id: user.id,
      username: username,
      email: user.email,
      prompt_name: promptName,
      topic: topic,
      prompt: promptText
    }
  });
}

return output;
